class Solution {
    public int numSub(String s) {
        int MOD = (int) 1e9 + 7;
        int count = 0;
        int total = 0;
        for (char c : s.toCharArray()) {
            if (c == '1') {
                count++;
            } else {
                total = (total + (count * (count + 1)) / 2) % MOD;
                count = 0;
            }
        }
        return (total + (count * (count + 1)) / 2) % MOD;
    }
}
